steps.run:
$bump = "${{ github.event.inputs.bump || 'patch' }}"
$versionFile = "version.json"
$current = (Get-Content $versionFile | ConvertFrom-Json).version
$parts = $current.Split('.')
switch ($bump) {
  'major' { $parts[0] = [int]$parts[0] + 1; $parts[1] = '0'; $parts[2] = '0' }
  'minor' { $parts[1] = [int]$parts[1] + 1; $parts[2] = '0' }
  'patch' { $parts[2] = [int]$parts[2] + 1 }
}
$new = $parts -join '.'
@{ version = $new } | ConvertTo-Json | Set-Content $versionFile
# version.json is the single source of truth in v4 — the legacy
# dotbot.psd1 ModuleVersion bump retired alongside the PSGallery
# publish flow.
Write-Host "Bumped $current -> $new ($bump)"
"version=$new" >> $env:GITHUB_OUTPUT
